import React from "react";
import CustomBtn from "../common/CustomBtn";

function TeamBtns({ numButtons, selectedClass, selectedRegion,handleTeamBtn }) {

    return (
      <>
        {Array.from({ length: numButtons }, (_, index) => (
          <CustomBtn
            key={index}
            text={`${selectedRegion[1]}${selectedClass+1}${(index + 1).toString().padStart(2, '0')}`}
            btncolor={"pink"}
            onClick={() => handleTeamBtn(index)}
          />
        ))}
      </>
    );
  }
  
  export default TeamBtns;
